+// geminiTranscriptMeta holds the fields we need from a Gemini transcript JSON
+// to reconstruct the correct session file path during restore.
+type geminiTranscriptMeta struct {
+	ProjectHash string `json:"projectHash"`
+	StartTime   string `json:"startTime"`
+}
+
+// extractGeminiMeta extracts projectHash and startTime from raw Gemini transcript JSON.
+func extractGeminiMeta(transcript []byte) geminiTranscriptMeta {
+	var meta geminiTranscriptMeta
+	_ = json.Unmarshal(transcript, &meta) //nolint:errcheck // best-effort extraction
+	return meta
+}
+
+// geminiSessionFileName constructs the Gemini session filename from the agent session ID and start time.
+// Gemini uses the format: session-<YYYY-MM-DDTHH-MM>-<shortid>.json
+func geminiSessionFileName(agentSessionID string, startTime string) string {
+	shortID := agentSessionID
+	if len(shortID) > 8 {
+		shortID = shortID[:8]
+	}
+
+	if startTime == "" {
+		return agentSessionID + ".json"
+	}
+
+	// startTime from transcript is like "2026-02-10T23:57:30.123Z"
+	// Gemini filename uses "2026-02-10T23-57" (colons replaced with dashes, truncated to minute)
+	t, err := time.Parse(time.RFC3339, startTime)
+	if err != nil {
+		// Try parsing just the date+time portion without timezone
+		if len(startTime) >= 16 {
+			t, err = time.Parse("2006-01-02T15:04", startTime[:16])
+		}
+		if err != nil {
+			return agentSessionID + ".json"
+		}
+	}
+	return fmt.Sprintf("session-%s-%s.json", t.Format("2006-01-02T15-04"), shortID)
+}
